import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Navbar from "../../components/Navbar";
import styles from "./ReceiptPage.module.css";

const ReceiptPage = () => {
  const { state } = useLocation();
  const navigate = useNavigate();

  if (!state) {
    return (
      <>
        <Navbar />
        <div className={styles.container}>
          <h2>No receipt data found</h2>
        </div>
      </>
    );
  }

  const { form, pkg, hotel, total, gst } = state;

  const bookingId = "BOOK" + Math.floor(100000 + Math.random() * 900000);

  const handlePrint = () => {
    window.print();
  };

  return (
    <>
      <Navbar />

      <div className={styles.container}>
        <div className={styles.card}>

          <h1>Booking Receipt</h1>
          <p className={styles.success}>✔ Payment Successful</p>

          <hr />

          {/* CUSTOMER */}
          <div className={styles.section}>
            <h3>Customer Details</h3>
            <p><b>Name:</b> {form.name}</p>
            <p><b>Email:</b> {form.email}</p>
            <p><b>Phone:</b> {form.phone}</p>
          </div>

          <hr />

          {/* BOOKING */}
          <div className={styles.section}>
            <h3>Booking Details</h3>
            <p><b>Booking ID:</b> {bookingId}</p>
            <p><b>Package:</b> {pkg.name}</p>
            <p><b>Hotel:</b> {hotel.name}</p>
          </div>

          <hr />

          {/* PAYMENT */}
          <div className={styles.section}>
            <h3>Payment Summary</h3>
            <p>Package Price: ₹{pkg.price}</p>
            <p>Hotel Price: ₹{hotel.pricePerDay}</p>
            <p>GST: ₹{gst}</p>

            <h2>Total Paid: ₹{total}</h2>
            <p><b>Payment Method:</b> {form.method}</p>
          </div>

          <hr />

          {/* BUTTONS */}
          <div className={styles.buttons}>
            <button onClick={handlePrint}>Download / Print Receipt</button>
            <button onClick={() => navigate("/my-bookings")}>
              View My Bookings
            </button>
          </div>

        </div>
      </div>
    </>
  );
};

export default ReceiptPage;
